// ReviewController.cs
using System;
using System.Collections.Generic;
using System.Data.Entity;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Assuming you have a model named 'Review' in this namespace

namespace YourNamespace.Controllers
{
    public class ReviewController : Controller
    {
        private ApplicationDbContext db = new ApplicationDbContext();  // Assuming you have an entity framework context named 'ApplicationDbContext'

        // GET: Reviews for a specific product
        public ActionResult Index(int id)
        {
            var reviews = db.Reviews.Where(r => r.ProductId == id).ToList();
            
            return View(reviews);
        }
        
        [HttpPost]
        public ActionResult Create([Bind(Include="Author,Content")] Review review)  // Assuming 'Author' and 'Content' are the properties of your Review model
        {
            if (ModelState.IsValid)
            {
                db.Reviews.Add(review);
                db.SaveChanges();
                
                return RedirectToAction("Index", new { id = review.ProductId });  // Redirect to the reviews page for the product that was reviewed
            }
            
            return View(review);
        }
    }
}